mapper.select:

where resource_id = #{resourceId}
order by create_time desc, task_id desc
limit 1


where task_status = 'pending'
order by create_time asc, task_id asc
limit #{batchSize}


where resource_id = #{resourceId}
  and task_type = #{taskType}
  and task_status = 'failed'
order by update_time desc, task_id desc
limit 1
